python -c "exec("""import os, datetime, re
root=r'C:\\Users\\016551\\OneDrive\\Desktop\\SwimPro'
start=0; limit=90
temp_re=re.compile(r'(^~\$|\.(tmp|temp|bak|backup|old|orig|swp|swo|part|crdownload|download|log|cache|pyc)$|^~|\.$|^(Thumbs\.db|desktop\.ini|\.DS_Store)$)', re.I)
proc_names={'.cursor','.vscode','cursor_sync','_sync','__pycache__'}
def esc(s): return s.encode('unicode_escape').decode('ascii')
def mt(p):
    try: return datetime.datetime.fromtimestamp(os.path.getmtime(p)).strftime('%Y-%m-%d %H:%M:%S')
    except Exception: return 'ERR'
def fsize(p):
    try: return os.path.getsize(p)
    except Exception: return 0
def dsize(p):
    total=0
    for dp, dns, fns in os.walk(p):
        for fn in fns:
            total += fsize(os.path.join(dp,fn))
    return total
items=[(root, True)]
for dp,dns,fns in os.walk(root):
    dns.sort(key=str.lower); fns.sort(key=str.lower)
    for d in dns: items.append((os.path.join(dp,d), True))
    for f in fns: items.append((os.path.join(dp,f), False))
items.sort(key=lambda x: os.path.relpath(x[0], root).lower())
lines=[]
for p,isdir in items:
    rel='.' if p==root else os.path.relpath(p, root)
    depth=0 if rel=='.' else rel.count(os.sep)+1
    name=os.path.basename(p) if rel!='.' else os.path.basename(root)
    size=dsize(p) if isdir else fsize(p)
    flags=[]
    if temp_re.search(name): flags.append('TEMP?')
    if name in proc_names or any(part in proc_names for part in rel.split(os.sep)): flags.append('PROCESS?')
    lines.append(f'{len(lines)+1:04d} '+('  '*depth)+f'[{'D' if isdir else 'F'}] {esc(name)} | rel={esc(rel)} | size={size} bytes | modified={mt(p)}'+((' | flags='+','.join(flags)) if flags else ''))
print(f'ROOT {esc(root)} | total_entries={len(lines)} | showing={start+1}-{min(start+limit,len(lines))}')
print('\n'.join(lines[start:start+limit]))""")"
